import React, { useState } from 'react';

function ProductCard({ id, title, category, price, originalPrice, discount, tag, onQuickView }) {
  const [inCart, setInCart] = useState(false);
  const [favorito, setFavorito] = useState(false);

  const handleAddToCart = async () => {
    try {
      // Simulación: podrías usar fetch o axios para enviar a tu backend
      console.log(`POST /api/cart/add/${id}`);
      setInCart(true);
    } catch (error) {
      console.error("Error al añadir al carrito", error);
    }
  };

  const handleToggleWishlist = () => {
    setFavorito(!favorito);
    console.log(`${favorito ? "Quitado de" : "Agregado a"} favoritos`);
  };

  return (
    <div className="product-card fade-in" style={{ animationDelay: '0.3s' }}>
      {tag && <span className="card-tag">{tag}</span>}
      <div className="img-container">
        <img src="/api/placeholder/400/320" alt="Zapatilla" className="product-img" />
        <div className="card-overlay"></div>
        <button className="quick-view" onClick={onQuickView}>Vista Rápida</button>
      </div>
      <div className="card-content">
        <div className="rating">
          <span className="star">★</span>
          <span className="star">★</span>
          <span className="star">★</span>
          <span className="star">★</span>
          <span className="star">☆</span>
        </div>
        <h3 className="card-title">{title}</h3>
        <p className="card-category">{category}</p>
        <div className="price-row">
          <div>
            <span className="price">${price}</span>
            {originalPrice && <span className="original-price">${originalPrice}</span>}
          </div>
          {discount && <span>{discount}% OFF</span>}
        </div>
        <div className="card-actions">
          <button
            className={`add-cart-btn ${inCart ? 'added' : ''}`}
            onClick={handleAddToCart}
            disabled={inCart}
          >
            {inCart ? 'Agregado ✅' : 'Añadir al Carrito'}
          </button>
          <button className="wishlist-btn" onClick={handleToggleWishlist}>
            <svg
              className="heart-icon"
              xmlns="http://www.w3.org/2000/svg"
              fill={favorito ? 'red' : 'none'}
              viewBox="0 0 24 24"
              stroke="currentColor"
            >
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2"
                d="M4.318 6.318a4.5 4.5 0 000 6.364L12 20.364l7.682-7.682a4.5 4.5 0 00-6.364-6.364L12 7.636l-1.318-1.318a4.5 4.5 0 00-6.364 0z"
              />
            </svg>
          </button>
        </div>
      </div>
    </div>
  );
}

export default ProductCard;
